record.field:
for line in record:
    if line.x_end_date and line.x_end_date < line.x_start_date: raise UserError("End Date must be empty or after Start Date.")
    domain = [('id', '!=', line.id), ('x_property_id', '=', line.x_property_id.id), ('x_start_date', '!=', False), '|', ('x_end_date', '=', False), ('x_end_date', '>=', line.x_start_date)]
    if line.x_end_date: domain.append(('x_start_date', '<=', line.x_end_date))
    if env['x_property_tenant'].search_count(domain, limit=1): raise UserError("Tenant dates cannot overlap for the same property. Ensure that tenancy periods do not overlap.")
